public class MajorityElement {
    // Boyer-Moore: candidate 'wins' — majority survives cancellation
    public static int majorityElement(int[] nums) {
        int candidate = nums[0], count = 1;
        for (int i = 1; i < nums.length; i++) {
            if (nums[i] == candidate) {
                count++;
            } else {
                count--;
                if (count == 0) { // candidate eliminated
                    candidate = nums[i];
                    count = 1;
                }
            }
        }
        return candidate; // majority element guaranteed to exist
    }
    public static void main(String[] args) {
        System.out.println(majorityElement(new int[]{3,2,3}));           // 3
        System.out.println(majorityElement(new int[]{2,2,1,1,1,2,2})); // 2
        System.out.println(majorityElement(new int[]{1}));              // 1
        System.out.println("O(n) time, O(1) space — Boyer-Moore voting");
        System.out.println("Intuition: majority cancels all minorities and still survives");
    }
}

