import java.util.Arrays;
public class NextPermutation {
    public static void nextPermutation(int[] nums) {
        int n = nums.length;
        // Step 1: find rightmost i where nums[i] < nums[i+1]
        int i = n - 2;
        while (i >= 0 && nums[i] >= nums[i+1]) i--;
        if (i >= 0) {
            // Step 2: find rightmost j > i where nums[j] > nums[i]
            int j = n - 1;
            while (nums[j] <= nums[i]) j--;
            // Swap i and j:
            int tmp = nums[i]; nums[i] = nums[j]; nums[j] = tmp;
        }
        // Step 3: reverse suffix from i+1 to end
        int lo = i + 1, hi = n - 1;
        while (lo < hi) {
            int tmp = nums[lo]; nums[lo] = nums[hi]; nums[hi] = tmp;
            lo++; hi--;
        }
    }
    public static void main(String[] args) {
        int[] a={1,2,3}; nextPermutation(a); System.out.println(Arrays.toString(a)); // [1,3,2]
        int[] b={3,2,1}; nextPermutation(b); System.out.println(Arrays.toString(b)); // [1,2,3]
        int[] c={1,1,5}; nextPermutation(c); System.out.println(Arrays.toString(c)); // [1,5,1]
        System.out.println("O(n) time, O(1) space — 3-step in-place");
    }
}

