import java.util.*;
public class LongestConsecutive {
    public static int longestConsecutive(int[] nums) {
        Set<Integer> set = new HashSet<>();
        for (int n : nums) set.add(n);
        int maxLen = 0;
        for (int n : set) {
            // Only start counting from sequence beginning:
            if (!set.contains(n - 1)) { // n is a sequence start
                int curr = n, len = 1;
                while (set.contains(curr + 1)) { curr++; len++; }
                maxLen = Math.max(maxLen, len);
            }
        }
        return maxLen;
    }
    public static void main(String[] args) {
        System.out.println(longestConsecutive(new int[]{100,4,200,1,3,2}));     // 4
        System.out.println(longestConsecutive(new int[]{0,3,7,2,5,8,4,6,0,1})); // 9
        System.out.println("O(n) time O(n) space — HashSet + start detection");
    }
}

