import java.util.Arrays;
public class RotateArray {
    static void reverse(int[] nums, int lo, int hi) {
        while (lo < hi) { int tmp=nums[lo]; nums[lo]=nums[hi]; nums[hi]=tmp; lo++; hi--; }
    }
    public static void rotate(int[] nums, int k) {
        int n = nums.length;
        k %= n; // handle k > n
        if (k == 0) return;
        reverse(nums, 0, n-1);   // reverse all
        reverse(nums, 0, k-1);   // reverse first k
        reverse(nums, k, n-1);   // reverse remaining
    }
    public static void main(String[] args) {
        int[] a={1,2,3,4,5,6,7}; rotate(a,3);
        System.out.println(Arrays.toString(a)); // [5,6,7,1,2,3,4]
        int[] b={-1,-100,3,99};  rotate(b,2);
        System.out.println(Arrays.toString(b)); // [3,99,-1,-100]
        System.out.println("O(n) time, O(1) space — 3 reversals");
        System.out.println("Why it works: reverse(all) then reverse(parts) = rotate");
    }
}

