public class MaxProductSubarray {
    public static int maxProduct(int[] nums) {
        int maxProd = nums[0], minProd = nums[0], result = nums[0];
        for (int i = 1; i < nums.length; i++) {
            int n = nums[i];
            // Negative flips max and min:
            if (n < 0) { int tmp = maxProd; maxProd = minProd; minProd = tmp; }
            maxProd = Math.max(n, maxProd * n); // extend or restart
            minProd = Math.min(n, minProd * n);
            result = Math.max(result, maxProd);
        }
        return result;
    }
    public static void main(String[] args) {
        System.out.println(maxProduct(new int[]{2,3,-2,4})); // 6
        System.out.println(maxProduct(new int[]{-2,0,-1}));  // 0
        System.out.println(maxProduct(new int[]{-2,3,-4}));  // 24
        System.out.println("O(n) time, O(1) space — Kadane's extended with min tracking");
    }
}

