public class MaxSumCircular {
    public static int maxSubarraySumCircular(int[] nums) {
        int total = 0, maxSum = nums[0], minSum = nums[0];
        int currMax = 0, currMin = 0;
        for (int n : nums) {
            // Kadane for max:
            currMax = Math.max(n, currMax + n);
            maxSum = Math.max(maxSum, currMax);
            // Kadane for min (to find what to exclude):
            currMin = Math.min(n, currMin + n);
            minSum = Math.min(minSum, currMin);
            total += n;
        }
        // If all negative: can't use circular (total-minSum would be 0 = empty array)
        if (maxSum < 0) return maxSum;
        return Math.max(maxSum, total - minSum);
    }
    public static void main(String[] args) {
        System.out.println(maxSubarraySumCircular(new int[]{1,-2,3,-2})); // 3
        System.out.println(maxSubarraySumCircular(new int[]{5,-3,5}));    // 10
        System.out.println(maxSubarraySumCircular(new int[]{-3,-2,-3}));  // -2
        System.out.println("O(n) — two simultaneous Kadane's (max and min)");
        System.out.println("Circular max = max(linear max, total - linear min)");
    }
}

