public class JumpGameII {
    public static int jump(int[] nums) {
        int jumps = 0, currentEnd = 0, farthest = 0;
        for (int i = 0; i < nums.length - 1; i++) {
            farthest = Math.max(farthest, i + nums[i]);
            if (i == currentEnd) { // reached end of current jump range
                jumps++;           // must make another jump
                currentEnd = farthest; // extend to farthest reachable
            }
        }
        return jumps;
    }
    public static void main(String[] args) {
        System.out.println(jump(new int[]{2,3,1,1,4})); // 2
        System.out.println(jump(new int[]{2,3,0,1,4})); // 2
        System.out.println(jump(new int[]{1}));          // 0
        System.out.println("O(n) greedy — BFS levels = jumps");
    }
}

