public class MaxGap {
    public static int maximumGap(int[] nums) {
        if (nums.length < 2) return 0;
        int n = nums.length;
        int min = nums[0], max = nums[0];
        for (int x : nums) { min = Math.min(min, x); max = Math.max(max, x); }
        if (min == max) return 0;
        // Pigeonhole: max gap >= (max-min)/(n-1)
        // Create n-1 buckets, each of size ceil((max-min)/(n-1))
        int bucketSize = Math.max(1, (max - min) / (n - 1));
        int bucketCount = (max - min) / bucketSize + 1;
        int[] bMin = new int[bucketCount], bMax = new int[bucketCount];
        java.util.Arrays.fill(bMin, Integer.MAX_VALUE);
        java.util.Arrays.fill(bMax, Integer.MIN_VALUE);
        for (int x : nums) {
            int b = (x - min) / bucketSize;
            bMin[b] = Math.min(bMin[b], x);
            bMax[b] = Math.max(bMax[b], x);
        }
        int maxGap = 0, prevMax = min;
        for (int b = 0; b < bucketCount; b++) {
            if (bMin[b] == Integer.MAX_VALUE) continue; // empty bucket
            maxGap = Math.max(maxGap, bMin[b] - prevMax);
            prevMax = bMax[b];
        }
        return maxGap;
    }
    public static void main(String[] args) {
        System.out.println(maximumGap(new int[]{3,6,9,1}));     // 3
        System.out.println(maximumGap(new int[]{10}));           // 0
        System.out.println(maximumGap(new int[]{1,10000000}));   // 9999999
        System.out.println("O(n) time/space — bucket sort insight");
    }
}

