import java.util.*;
public class SubarrayXOR {
    public static int countSubarraysWithXorK(int[] nums, int k) {
        // prefix XOR pattern: xor[j] ^ xor[i] = k → xor[i] = xor[j] ^ k
        Map<Integer,Integer> prefixCount = new HashMap<>();
        prefixCount.put(0, 1); // empty prefix has XOR = 0
        int xor = 0, count = 0;
        for (int n : nums) {
            xor ^= n;                                              // running prefix XOR
            count += prefixCount.getOrDefault(xor ^ k, 0);        // how many i's satisfy condition
            prefixCount.merge(xor, 1, Integer::sum);
        }
        return count;
    }
    public static void main(String[] args) {
        System.out.println(countSubarraysWithXorK(new int[]{4,2,2,6,4}, 6)); // 4
        System.out.println(countSubarraysWithXorK(new int[]{5,6,7,8,9}, 5)); // 2
        System.out.println("O(n) — identical pattern to subarraySum==k but with XOR");
        System.out.println("XOR property: a^b=k → a = b^k (XOR is self-inverse)");
    }
}

