import java.util.*;
public class ArraySynthesis {
    static int maxSubarray(int[] nums){
        int c=nums[0],m=nums[0]; for(int i=1;i<nums.length;i++){c=Math.max(nums[i],c+nums[i]);m=Math.max(m,c);} return m;
    }
    static int majorityElement(int[] nums){
        int cand=nums[0],cnt=1; for(int i=1;i<nums.length;i++){if(nums[i]==cand)cnt++;else{cnt--;if(cnt==0){cand=nums[i];cnt=1;}}} return cand;
    }
    static void nextPermutation(int[] nums){
        int n=nums.length,i=n-2;
        while(i>=0&&nums[i]>=nums[i+1])i--;
        if(i>=0){int j=n-1;while(nums[j]<=nums[i])j--;int t=nums[i];nums[i]=nums[j];nums[j]=t;}
        int lo=i+1,hi=n-1; while(lo<hi){int t=nums[lo];nums[lo]=nums[hi];nums[hi]=t;lo++;hi--;}
    }
    static int longestConsecutive(int[] nums){
        Set<Integer> s=new HashSet<>(); for(int n:nums)s.add(n);
        int max=0; for(int n:s){if(!s.contains(n-1)){int c=n,len=1;while(s.contains(++c))len++;max=Math.max(max,len);}}
        return max;
    }
    static void rotate(int[] nums, int k){
        int n=nums.length; k%=n; if(k==0)return;
        rev(nums,0,n-1); rev(nums,0,k-1); rev(nums,k,n-1);
    }
    static void rev(int[] a,int l,int r){while(l<r){int t=a[l];a[l]=a[r];a[r]=t;l++;r--;}}

    public static void main(String[] args){
        System.out.println("1. maxSubarray([-2,1,-3,4,-1,2,1,-5,4])=" + maxSubarray(new int[]{-2,1,-3,4,-1,2,1,-5,4}));
        System.out.println("2. majorityElement([2,2,1,1,1,2,2])=" + majorityElement(new int[]{2,2,1,1,1,2,2}));
        int[] np={1,2,3}; nextPermutation(np);
        System.out.println("3. nextPermutation([1,2,3])=" + Arrays.toString(np));
        System.out.println("4. longestConsecutive([100,4,200,1,3,2])=" + longestConsecutive(new int[]{100,4,200,1,3,2}));
        int[] ra={1,2,3,4,5,6,7}; rotate(ra,3);
        System.out.println("5. rotate([1..7],3)=" + Arrays.toString(ra));
        boolean allPass = maxSubarray(new int[]{-2,1,-3,4,-1,2,1,-5,4})==6
            && majorityElement(new int[]{2,2,1,1,1,2,2})==2
            && Arrays.equals(np,new int[]{1,3,2})
            && longestConsecutive(new int[]{100,4,200,1,3,2})==4
            && Arrays.equals(ra,new int[]{5,6,7,1,2,3,4});
        System.out.println("All pass: "+allPass);
    }
}
